export const CheckoutStatusEnumSchema = z.enum(["incomplete","requires_escalation","ready_for_complete","complete_in_progress","completed","canceled"]).describe("Checkout state indicating the current phase and required action. See Checkout Status lifecycle documentation for state transition details.");
export type CheckoutStatusEnum = z.infer<typeof CheckoutStatusEnumSchema>;

export const DiscountAppliedDiscountMethodEnumSchema = z.enum(["each","across"]).describe("Allocation method. 'each' = applied independently per item. 'across' = split proportionally by value.");
export type DiscountAppliedDiscountMethodEnum = z.infer<typeof DiscountAppliedDiscountMethodEnumSchema>;

export const AdjustmentStatusEnumSchema = z.enum(["pending","completed","failed"]).describe("Adjustment status.");
export type AdjustmentStatusEnum = z.infer<typeof AdjustmentStatusEnumSchema>;

export const ExpectationMethodTypeEnumSchema = z.enum(["shipping","pickup","digital"]).describe("Delivery method type (shipping, pickup, digital).");
export type ExpectationMethodTypeEnum = z.infer<typeof ExpectationMethodTypeEnumSchema>;

export const FulfillmentAvailableMethodTypeEnumSchema = z.enum(["shipping","pickup"]).describe("Fulfillment method type this availability applies to.");
export type FulfillmentAvailableMethodTypeEnum = z.infer<typeof FulfillmentAvailableMethodTypeEnumSchema>;

export const FulfillmentMethodTypeEnumSchema = z.enum(["shipping","pickup"]).describe("Fulfillment method type.");
export type FulfillmentMethodTypeEnum = z.infer<typeof FulfillmentMethodTypeEnumSchema>;

export const MessageErrorContentTypeEnumSchema = z.enum(["plain","markdown"]).describe("Content format, default = plain.");
export type MessageErrorContentTypeEnum = z.infer<typeof MessageErrorContentTypeEnumSchema>;

export const MessageErrorSeverityEnumSchema = z.enum(["recoverable","requires_buyer_input","requires_buyer_review"]).describe("Declares who resolves this error. 'recoverable': agent can fix via API. 'requires_buyer_input': merchant requires information their API doesn't support collecting programmatically (checkout incomplete). 'requires_buyer_review': buyer must authorize before order placement due to policy, regulatory, or entitlement rules (checkout complete). Errors with 'requires_*' severity contribute to 'status: requires_escalation'.");
export type MessageErrorSeverityEnum = z.infer<typeof MessageErrorSeverityEnumSchema>;

export const MessageInfoContentTypeEnumSchema = z.enum(["plain","markdown"]).describe("Content format, default = plain.");
export type MessageInfoContentTypeEnum = z.infer<typeof MessageInfoContentTypeEnumSchema>;

export const MessageWarningContentTypeEnumSchema = z.enum(["plain","markdown"]).describe("Content format, default = plain.");
export type MessageWarningContentTypeEnum = z.infer<typeof MessageWarningContentTypeEnumSchema>;

export const OrderLineItemStatusEnumSchema = z.enum(["processing","partial","fulfilled"]).describe("Derived status: fulfilled if quantity.fulfilled == quantity.total, partial if quantity.fulfilled > 0, otherwise processing.");
export type OrderLineItemStatusEnum = z.infer<typeof OrderLineItemStatusEnumSchema>;

export const TotalTypeEnumSchema = z.enum(["items_discount","subtotal","discount","fulfillment","tax","fee","total"]).describe("Type of total categorization.");
export type TotalTypeEnum = z.infer<typeof TotalTypeEnumSchema>;

export const ProfileSchemaSigningKeyUseEnumSchema = z.enum(["sig","enc"]).describe("Key usage. Should be 'sig' for signing keys.");
export type ProfileSchemaSigningKeyUseEnum = z.infer<typeof ProfileSchemaSigningKeyUseEnumSchema>;
